import {SpotterMainApp} from "../type";
import {
    addErrorHandler,
    addGlobalUncaughtErrorHandler,
    FrameworkConfiguration,
    removeErrorHandler,
    removeGlobalUncaughtErrorHandler,
    runAfterFirstMounted,
    setDefaultMountApp, start
} from "qiankun";
import {startMainAcp, startSubAcp} from "./app-communication-protocol";
import {registerApps} from "./appRegistry";

export interface MicroAppSystemOptions extends FrameworkConfiguration{
    acp: Parameters<typeof startMainAcp>[0],
    globalUncaughtErrorHandler?: Parameters<typeof addGlobalUncaughtErrorHandler>[0]
    errorHandler?: Parameters<typeof addErrorHandler>[0]
    runAfterFirstMounted?: Parameters<typeof runAfterFirstMounted>[0]
    setDefaultMountApp?: Parameters<typeof setDefaultMountApp>[0]
}
export function boostrapMicroAppSystem(options: MicroAppSystemOptions, sptApp: SpotterMainApp){
    sptApp.microApp = {} as any
    options.globalUncaughtErrorHandler && addGlobalUncaughtErrorHandler(options.globalUncaughtErrorHandler)
    options.errorHandler && addErrorHandler(options.errorHandler)
    options.runAfterFirstMounted && runAfterFirstMounted(options.runAfterFirstMounted)
    options.setDefaultMountApp && setDefaultMountApp(options.setDefaultMountApp)

    startMainAcp(options?.acp)

    const {acp, ...startOptions} = options
    start(startOptions)
    sptApp.microApp.startSubAcp = startSubAcp
    sptApp.microApp.registerApps = registerApps
    sptApp.microApp.addErrorHandler = addErrorHandler
    sptApp.microApp.addGlobalUncaughtErrorHandler = addGlobalUncaughtErrorHandler
    sptApp.microApp.removeErrorHandler = removeErrorHandler
    sptApp.microApp.removeGlobalUncaughtErrorHandler = removeGlobalUncaughtErrorHandler
}
